CATEGORY_INFO = {0: ("Good","🟢","#2E7D32","Air quality is satisfactory. Safe for everyone!"), 1: ("Moderate","🟡","#F9A825","Acceptable. Sensitive people should limit outdoor activity."), 2: ("Unhealthy for Sensitive Groups","🟠","#E65100","Children & elderly should reduce outdoor exposure."), 3: ("Unhealthy","🔴","#B71C1C","Everyone may experience health effects. Stay indoors!"), 4: ("Very Unhealthy","🟣","#6A1B9A","Health alert! Avoid all outdoor activities."), 5: ("Hazardous","🟤","#4E342E","Emergency! Dangerous for everyone. Stay inside!")}

@st.cache_resource
def load_models():
    reg  = joblib.load('models/best_regression_model.pkl')
    clf  = joblib.load('models/best_classification_model.pkl')
    prep = joblib.load('models/preprocessor.pkl')
    return reg, clf, prep

reg_model, clf_model, preprocessor = load_models()

# Header
st.title("🌫️ AirSight — Next Day AQI Predictor")
st.markdown("**Predict tomorrow's Air Quality Index using Machine Learning**")
st.info("📦 Covers **54 US States & Territories** | **3,000+ Counties** | Source: EPA AirData 2024")
st.divider()

# Sidebar
st.sidebar.header("📍 Select Location")
state_name = st.sidebar.selectbox("Select State", sorted(STATE_CODE_MAP.keys()), index=sorted(STATE_CODE_MAP.keys()).index("California"))
county_list = STATE_COUNTY_MAP.get(state_name, [])
county_name = st.sidebar.selectbox("Select County", county_list)
state_code  = STATE_CODE_MAP.get(state_name, 6)
county_code = COUNTY_CODE_MAP.get(f"{state_name}||{county_name}", 37)
st.sidebar.caption(f"State Code: `{state_code}` | County Code: `{county_code}`")

st.sidebar.divider()
pollutant = st.sidebar.selectbox("🏭 Dominant Pollutant", ["Ozone","PM2.5","PM10","NO2","CO"])

st.sidebar.divider()
st.sidebar.subheader("📅 Date")
today        = datetime.date.today()
month        = st.sidebar.slider("Month", 1, 12, today.month)
day_of_week  = st.sidebar.slider("Day of Week (0=Mon, 6=Sun)", 0, 6, today.weekday())
quarter      = (month - 1) // 3 + 1
day_of_year  = datetime.date(today.year, month, 15).timetuple().tm_yday
week_of_year = int(datetime.date(today.year, month, 15).strftime("%V"))
season       = {1:0,2:0,3:1,4:1,5:1,6:2,7:2,8:2,9:3,10:3,11:3,12:0}[month]
is_weekend   = 1 if day_of_week >= 5 else 0
num_sites    = st.sidebar.slider("Monitoring Sites", 1, 10, 2)

st.sidebar.divider()
st.sidebar.subheader("📊 Recent AQI Values")
aqi_lag1 = st.sidebar.number_input("Yesterday AQI",  1, 500, 45)
aqi_lag2 = st.sidebar.number_input("2 Days Ago AQI", 1, 500, 42)
aqi_lag3 = st.sidebar.number_input("3 Days Ago AQI", 1, 500, 48)
aqi_lag7 = st.sidebar.number_input("1 Week Ago AQI", 1, 500, 40)

rolling_mean_3 = round((aqi_lag1+aqi_lag2+aqi_lag3)/3, 2)
rolling_mean_7 = round((aqi_lag1+aqi_lag2+aqi_lag3+aqi_lag7)/4, 2)
rolling_std_7  = round(float(np.std([aqi_lag1,aqi_lag2,aqi_lag3,aqi_lag7])), 2)

# Top panel
col1,col2,col3,col4 = st.columns(4)
with col1: st.metric("📍 State",         state_name)
with col2: st.metric("🏘️ County",        county_name)
with col3: st.metric("📅 Yesterday AQI", aqi_lag1)
with col4: st.metric("📈 7-Day Avg",     rolling_mean_7)

st.divider()

if st.button("🔮 Predict Tomorrow's AQI", use_container_width=True, type="primary"):
    input_data = pd.DataFrame([{"AQI_lag1":aqi_lag1,"AQI_lag2":aqi_lag2,"AQI_lag3":aqi_lag3,"AQI_lag7":aqi_lag7,"AQI_rolling_mean_3":rolling_mean_3,"AQI_rolling_mean_7":rolling_mean_7,"AQI_rolling_std_7":rolling_std_7,"Month":month,"Day_of_Week":day_of_week,"Quarter":quarter,"Day_of_Year":day_of_year,"Week_of_Year":week_of_year,"Season":season,"Is_Weekend":is_weekend,"Num_Sites_Reporting":num_sites,"State_Code":state_code,"County_Code":county_code,"State_Name":state_name,"County_Name":county_name,"Defining_Parameter":pollutant}])

    inp = preprocessor.transform(input_data)
    predicted_aqi = max(1, min(500, round(float(reg_model.predict(inp)[0]), 1)))
    predicted_cat = clf_model.predict(inp)[0]
    cat_name, emoji, color, advice = CATEGORY_INFO[predicted_cat]

    st.subheader("🎯 Prediction Results")
    c1, c2 = st.columns(2)
    with c1:
        st.markdown(f"<div style='background:{color};padding:35px;border-radius:15px;text-align:center'><h1 style='color:white;font-size:70px;margin:0'>{predicted_aqi}</h1><h3 style='color:white;margin:5px 0 0 0'>Predicted AQI</h3><p style='color:white;margin:5px 0 0 0'>{county_name}, {state_name}</p></div>", unsafe_allow_html=True)
    with c2:
        st.markdown(f"<div style='background:{color};padding:35px;border-radius:15px;text-align:center'><h1 style='color:white;font-size:60px;margin:0'>{emoji}</h1><h3 style='color:white;margin:5px 0 0 0'>{cat_name}</h3><p style='color:white;margin:5px 0 0 0'>Tomorrow's Category</p></div>", unsafe_allow_html=True)

    st.divider()
    st.subheader("💊 Health Advice")
    st.warning(f"{emoji} **{cat_name}** — {advice}")

    st.subheader("📊 AQI Reference Scale")
    st.table(pd.DataFrame({"Status":["🟢","🟡","🟠","🔴","🟣","🟤"],"Category":["Good","Moderate","Unhealthy for Sensitive","Unhealthy","Very Unhealthy","Hazardous"],"AQI Range":["0–50","51–100","101–150","151–200","201–300","301–500"],"Who is at risk":["No one","Very sensitive","Sensitive groups","Everyone","Everyone","Everyone (Emergency)"]}))

st.divider()
